/**
 * Generate Daytona firewall config.
 *
 * Data sources:
 * - https://www.daytona.io/docs/getting-started
 * - https://www.daytona.io/docs/tools/api/
 *
 * Daytona uses Bearer token authentication for the platform API and toolbox
 * proxy endpoints. The SDK reads DAYTONA_API_KEY from the environment.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://www.daytona.io/docs/tools/api/";
const PLACEHOLDER_VALUE = "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocal";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Daytona API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:daytona",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const daytonaFirewall = {",
    '  name: "daytona",',
    '  description: "Daytona API",',
    "  placeholders: {",
    `    DAYTONA_API_KEY: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://app.daytona.io/api",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.DAYTONA_API_KEY }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "    {",
    '      base: "https://proxy.app.daytona.io/toolbox",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.DAYTONA_API_KEY }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];

  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Daytona firewall config...");
  const ts = generateTypeScript();
  writeOutput("daytona", ts, import.meta.dirname);
}
